static int rangeSumDirect(int[] arr, int left, int right) {
    int sum = 0;
    for (int i = left; i <= right; i++) {
        sum += arr[i];
    }
    return sum;
}

public class Main {
    public static void main(String[] args) {
        int[] arr = {2, 4, 1, 5, 3};
        int[] prefix = new int[arr.length];

        prefix[0] = arr[0];
        for (int i = 1; i < arr.length; i++) {
            prefix[i] = prefix[i - 1] + arr[i];
        }

        System.out.println(java.util.Arrays.toString(prefix));
    }
}

public class Main {
    static int rangeSum(int[] prefix, int left, int right) {
        if (left == 0) {
            return prefix[right];
        }
        return prefix[right] - prefix[left - 1];
    }

    public static void main(String[] args) {
        int[] arr = {2, 4, 1, 5, 3};
        int[] prefix = new int[arr.length];

        prefix[0] = arr[0];
        for (int i = 1; i < arr.length; i++) {
            prefix[i] = prefix[i - 1] + arr[i];
        }

        System.out.println(rangeSum(prefix, 1, 3)); // sum of arr[1..3]
        System.out.println(rangeSum(prefix, 0, 4)); // sum of the whole array
    }
}

public class Main {
    public static void main(String[] args) {
        int[] arr = {3, 1, 4, 1, 5, 9, 2, 6};
        int[] prefix = new int[arr.length];

        prefix[0] = arr[0];
        for (int i = 1; i < arr.length; i++) {
            prefix[i] = prefix[i - 1] + arr[i];
        }

        int[][] queries = {{0, 2}, {3, 5}, {1, 7}};
        for (int[] q : queries) {
            int left = q[0];
            int right = q[1];
            int sum = (left == 0) ? prefix[right] : prefix[right] - prefix[left - 1];
            System.out.println("Sum[" + left + ".." + right + "] = " + sum);
        }
    }
}

